-- Enable RLS
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;
ALTER TABLE orders FORCE ROW LEVEL SECURITY; -- áp dụng cả cho table owner

-- Policy: mỗi tenant chỉ thấy data của mình
CREATE POLICY orders_tenant_isolation ON orders
    USING (tenant_id = current_setting('app.current_tenant', TRUE)::INT);

-- Policy riêng cho SELECT, INSERT, UPDATE, DELETE
CREATE POLICY orders_select ON orders FOR SELECT
    USING (tenant_id = current_setting('app.current_tenant')::INT);

CREATE POLICY orders_insert ON orders FOR INSERT
    WITH CHECK (tenant_id = current_setting('app.current_tenant')::INT);

-- C# setup (EF Core connection interceptor)
public class TenantConnectionInterceptor(ICurrentTenantService tenantSvc)
    : DbConnectionInterceptor
{
    public override async Task ConnectionOpenedAsync(
        DbConnection conn, ConnectionEndEventData data, CancellationToken ct)
    {
        using var cmd = conn.CreateCommand();
        cmd.CommandText = $"SET app.current_tenant = {tenantSvc.CurrentTenantId}";
        await cmd.ExecuteNonQueryAsync(ct);
    }
}

